import { useActionState } from "react";
import { useFormStatus } from "react-dom";
import type { SyncResult } from "./page";

// ---------------------------------------------------------------------------
// Submit button — uses useFormStatus to show a pending spinner while the
// server action is in flight.  The button is disabled during submission to
// prevent accidental double-clicks / double-syncs.
// ---------------------------------------------------------------------------
function SubmitButton() {
  const { pending } = useFormStatus();

  return (
    <button
      type="submit"
      disabled={pending}
      style={{
        padding: "0.5rem 1rem",
        background: pending ? "#9ca3af" : "#2563eb",
        color: "#fff",
        border: "none",
        borderRadius: 6,
        cursor: pending ? "not-allowed" : "pointer",
        fontWeight: 500,
        fontSize: "0.875rem",
        display: "inline-flex",
        alignItems: "center",
        gap: "0.5rem",
        transition: "background 0.15s",
      }}
    >
      {pending && <Spinner />}
      {pending ? "Syncing…" : "Sync latest catalog"}
    </button>
  );
}

// ---------------------------------------------------------------------------
// Tiny inline SVG spinner — avoids any external dependency.
// ---------------------------------------------------------------------------
function Spinner() {
  return (
    <span style={{ display: "inline-block", width: 14, height: 14 }}>
      <svg viewBox="0 0 24 24" fill="none">
        <circle
          cx="12"
          cy="12"
          r="10"
          stroke="currentColor"
          strokeWidth="4"
          opacity="0.25"
        />
        <path
          d="M12 2a10 10 0 0 1 9.95 9"
          stroke="currentColor"
          strokeWidth="4"
          strokeLinecap="round"
        />
      </svg>
      <style>{`svg { animation: spin 1s linear infinite; } @keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </span>
  );
}

// ---------------------------------------------------------------------------
// SyncForm
//
// A client component that wraps the inline server action in useActionState so
// we can show a success / error message right on the form without a full-page
// navigation or client-side state management.
// ---------------------------------------------------------------------------
export function SyncForm({
  syncAction,
}: {
  syncAction: (
    prev: SyncResult | null,
    form: FormData,
  ) => Promise<SyncResult>;
}) {
  const [state, formAction] = useActionState(syncAction, null);

  return (
    <div>
      <form action={formAction}>
        <SubmitButton />
      </form>

      {/* ---- Inline feedback ---- */}
      {state && (
        <p
          style={{
            margin: "0.5rem 0 0",
            fontSize: "0.8125rem",
            color: state.success ? "#16a34a" : "#dc2626",
          }}
        >
          {state.message}
        </p>
      )}
    </div>
  );
}
"}

